    // FLUXO DE VERIFICAÇÃO DE IMPACTOS (Tramitação)

    test('Fluxo CHEFE: Realizar alterações e verificar impactos', async ({page}) => {
        // Debbie Harry possui apenas 1 perfil
        await login(page, USUARIO_CHEFE, SENHA_CHEFE);
