/**
 * Verifica que está na página do painel principal.
 */
export async function verificarPaginaPainel(page: Page): Promise<void> {
    await expect(page).toHaveURL(/\/painel/);
}

// Funções de Navegação

/**
 * Navega para um subprocesso clicando na célula da unidade na tabela TreeTable.
 * Se já estiver na página do subprocesso (redirecionamento direto), apenas valida.
 */
export async function navegarParaSubprocesso(
    page: Page,
    siglaUnidade: string
): Promise<void> {
    const urlSubprocesso = new RegExp(String.raw`/processo/\d+/${siglaUnidade}$`);

    // Se já estivermos na URL do subprocesso, não precisamos navegar
    if (urlSubprocesso.test(page.url())) {
        return;
    }

    // Aguardar o cabeçalho do processo (v-if="processo") para garantir carregamento inicial
    await expect(page.getByText('Carregando detalhes do processo...').first()).toBeHidden();

    // Se ainda não estivermos na URL, verificamos se o redirecionamento está em curso
    try {
        await page.waitForURL(urlSubprocesso, {timeout: 1000});
        return;
    } catch (e) {
        // Se não redirecionou em 1s, prossegue com clique manual
    }

    await expect(page.getByTestId('processo-info')).toBeVisible();

    const tabela = page.getByTestId('tbl-tree');
    await expect(tabela).toBeVisible();

    const celula = tabela.getByRole('cell', {name: siglaUnidade}).first();
    await expect(celula).toBeVisible();
    await celula.click();

    await expect(page).toHaveURL(urlSubprocesso);
}

import {expect, type Page} from '@playwright/test';

/**
 * Calcula uma data limite N dias no futuro
 */
export function calcularDataLimite(dias: number): string {
    const dataLimite = new Date();
    dataLimite.setDate(dataLimite.getDate() + dias);
    return dataLimite.toISOString().split('T')[0];
}

/**
 * Cria um processo através da UI
 */
export async function criarProcesso(page: Page, options: {
    descricao: string;
    tipo: 'MAPEAMENTO' | 'REVISAO' | 'DIAGNOSTICO';
    diasLimite: number;
    unidade: string | string[];
    expandir?: string[];
    iniciar?: boolean;
}): Promise<void> {
    await page.getByTestId('btn-painel-criar-processo').click();
    await expect(page).toHaveURL(/\/processo\/cadastro/);

    await page.getByTestId('inp-processo-descricao').fill(options.descricao);
    await page.getByTestId('sel-processo-tipo').selectOption(options.tipo);
    await page.getByTestId('inp-processo-data-limite').fill(calcularDataLimite(options.diasLimite));

    await expect(page.getByText('Carregando unidades...')).toBeHidden();
    if (options.expandir) {
        for (const sigla of options.expandir) {
            await page.getByTestId(`btn-arvore-expand-${sigla}`).click();
        }
    }

    const unidades = Array.isArray(options.unidade) ? options.unidade : [options.unidade];
    for (const u of unidades) {
        const checkbox = page.getByTestId(`chk-arvore-unidade-${u}`);
        await expect(checkbox).toBeVisible();
        if (!await checkbox.isEnabled()) {
            await expect(checkbox).toBeEnabled({timeout: 5000}).catch(() => {
                // segue para validar estado final após a janela de espera
            });
        }
        // Só marca se não estiver marcado (pode já estar marcado se o pai foi selecionado)
        if (!await checkbox.isChecked()) {
            if (!await checkbox.isEnabled()) {
                throw new Error(`Unidade ${u} não está selecionável para criação do processo.`);
            }
            await checkbox.check();
        }
    }

    if (options.iniciar) {
        await page.getByTestId('btn-processo-iniciar').click();
        await page.getByTestId('btn-iniciar-processo-confirmar').click();
    } else {
        await page.getByTestId('btn-processo-salvar').click();
    }
    await page.waitForURL('/painel');
}

